#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

my $log_dir = '/path/to/logs';
my $query = CGI->new;
print $query->header;

my $filename = $query->param('logfile');

if (defined $filename) {
    my $filepath = "$log_dir/$filename";
    
    if (-e $filepath && -r $filepath) {
        open(my $fh, '<', $filepath) or die "Cannot open file: $!";
        print "<pre>\n";
        while (my $line = <$fh>) {
            print $line;
        }
        close($fh);
        print "</pre>\n";
    } else {
        print "File not found or cannot be read.";
    }
} else {
    print "No log file specified.";
}